import { NavLink } from "react-router-dom";
import {
    Home,
    Users,
    Calendar,
    Settings,
    LayoutGrid,
    LogOut,
    ChevronLeft,
    ChevronRight,
    ShieldCheck,
    Briefcase,
    UserCircle,
    ScanSearch,
    KeyRound,
    PartyPopper,
    ScrollText,
    CalendarX,
} from "lucide-react";
import { useState } from "react";
import { useAuth } from "@/shared/AuthContext";
import { useAuditMode } from "@/shared/AuditModeContext";
import { PERMISSIONS } from "@/constants/permissions";
import { Badge } from "@/shadcn/components/ui/badge";
import { cn } from "@/shadcn/lib/utils";
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from "@/shadcn/components/ui/tooltip";

const menuItems = [
    { icon: Home,        label: "Dashboard",          path: "/" },
    { icon: Users,       label: "Manage Users",        path: "/users",                permission: PERMISSIONS.Employee.Read },
    { icon: ShieldCheck, label: "Roles & Permissions", path: "/roles",                permission: PERMISSIONS.Role.Read },
    { icon: KeyRound,    label: "My Permissions",      path: "/my-permissions" },
    { icon: Calendar,    label: "Work Schedule",        path: "/work-schedule",        permission: PERMISSIONS.WorkSchedule.Read },
    { icon: PartyPopper, label: "Public Holidays",     path: "/public-holidays",      permission: PERMISSIONS.PublicHoliday.Read },
    { icon: Briefcase,   label: "Customers",           path: "/customers",            permission: PERMISSIONS.Customer.Read },
    { icon: LayoutGrid,  label: "Assignments",         path: "/assignments",          permission: PERMISSIONS.ProjectAssignment.Read },
    { icon: Settings,    label: "Settings",            path: "/application-settings", permission: PERMISSIONS.ApplicationSettings.Read },
    { icon: ScrollText,  label: "System Logs",         path: "/logs",                 permission: PERMISSIONS.ApplicationSettings.Read },
    { icon: CalendarX,   label: "Leave Management",    path: "/leave-management",     permission: PERMISSIONS.Leave.Read },
];

export default function Sidebar() {
    const [collapsed, setCollapsed] = useState(false);
    const { user, logout, hasPermission } = useAuth();
    const { isAuditMode, toggleAuditMode } = useAuditMode();
    const isAdmin = user?.role === 'Admin';

    const filteredMenuItems = menuItems.filter(item =>
        !item.permission || hasPermission(item.permission)
    );

    return (
        <TooltipProvider>
            <aside
                className={cn(
                    "relative h-screen bg-sidebar border-r border-sidebar-border",
                    "transition-all duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] flex flex-col z-40",
                    collapsed ? "w-20" : "w-72"
                )}
            >
                {/* Logo */}
                <div className="h-20 flex items-center px-6">
                    <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-primary to-primary/60 flex items-center justify-center text-primary-foreground shadow-lg shadow-primary/20 shrink-0">
                            <span className="text-xl font-black italic">H</span>
                        </div>
                        {!collapsed && (
                            <span className="font-black text-xl tracking-tight text-sidebar-foreground leading-none">
                                HARMONY
                            </span>
                        )}
                    </div>
                </div>

                {/* Navigation */}
                <nav className="flex-1 py-6 px-4 space-y-1.5 overflow-y-auto no-scrollbar">
                    {filteredMenuItems.map((item) => (
                        <Tooltip key={item.path}>
                            <TooltipTrigger asChild>
                                <NavLink
                                    to={item.path}
                                    className={({ isActive }) => cn(
                                        "flex items-center gap-3 px-4 py-3 rounded-2xl transition-all duration-300 group relative",
                                        isActive
                                            ? "bg-sidebar-accent text-sidebar-primary font-bold"
                                            : "text-sidebar-foreground/60 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground"
                                    )}
                                >
                                    {({ isActive }) => (
                                        <>
                                            <item.icon className="w-5 h-5 shrink-0 transition-transform duration-300 group-hover:scale-110 group-active:scale-95" />
                                            {!collapsed && (
                                                <span className="text-sm tracking-tight truncate">{item.label}</span>
                                            )}
                                            {isActive && !collapsed && (
                                                <span className="absolute right-4 w-1.5 h-1.5 rounded-full bg-sidebar-primary animate-pulse" />
                                            )}
                                        </>
                                    )}
                                </NavLink>
                            </TooltipTrigger>
                            {collapsed && (
                                <TooltipContent side="right">
                                    {item.label}
                                </TooltipContent>
                            )}
                        </Tooltip>
                    ))}
                </nav>

                {/* Profile Section */}
                <div className="p-6 border-t border-sidebar-border">
                    {!collapsed ? (
                        <div className="space-y-4">
                            <NavLink
                                to="/profile"
                                className={({ isActive }) => cn(
                                    "flex items-center gap-4 p-2 rounded-2xl transition-all duration-300",
                                    isActive
                                        ? "bg-sidebar-accent border border-sidebar-border"
                                        : "hover:bg-sidebar-accent/60"
                                )}
                            >
                                <div className="w-12 h-12 rounded-2xl bg-sidebar-accent border border-sidebar-border flex items-center justify-center text-sidebar-foreground/60 shrink-0">
                                    <UserCircle className="w-7 h-7" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-black text-sidebar-foreground truncate">
                                        {user?.fullName || user?.email?.split('@')[0] || "Guest"}
                                    </p>
                                    <Badge
                                        variant="secondary"
                                        className="mt-1 opacity-70 bg-sidebar-accent text-sidebar-foreground/70 border-sidebar-border text-[10px] px-2 py-0.5 h-auto font-bold uppercase tracking-wider rounded-full"
                                    >
                                        {user?.role || "USER"}
                                    </Badge>
                                </div>
                            </NavLink>

                            {isAdmin && (
                                <button
                                    onClick={toggleAuditMode}
                                    className={cn(
                                        "w-full flex items-center gap-2.5 px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all",
                                        isAuditMode
                                            ? "text-amber-400 bg-amber-500/10 border border-amber-500/20 hover:bg-amber-500/15"
                                            : "text-sidebar-foreground/50 hover:text-sidebar-foreground hover:bg-sidebar-accent"
                                    )}
                                >
                                    <ScanSearch className="w-4 h-4 shrink-0" />
                                    <span className="flex-1 text-left">Audit Mode</span>
                                    {isAuditMode && (
                                        <span className="w-1.5 h-1.5 rounded-full bg-amber-400 animate-pulse" />
                                    )}
                                </button>
                            )}

                            <button
                                onClick={logout}
                                className="w-full flex items-center justify-center gap-2.5 px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-widest text-rose-500 hover:text-rose-400 hover:bg-rose-500/10 transition-all"
                            >
                                <LogOut className="w-4 h-4" />
                                Sign Out
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-2">
                            {isAdmin && (
                                <Tooltip>
                                    <TooltipTrigger asChild>
                                        <button
                                            onClick={toggleAuditMode}
                                            className={cn(
                                                "w-full flex items-center justify-center p-4 rounded-2xl transition-all",
                                                isAuditMode
                                                    ? "text-amber-400 bg-amber-500/10 border border-amber-500/20"
                                                    : "text-sidebar-foreground/50 hover:bg-sidebar-accent hover:text-sidebar-foreground"
                                            )}
                                        >
                                            <ScanSearch className="w-5 h-5" />
                                            {isAuditMode && (
                                                <span className="absolute top-2 right-2 w-1.5 h-1.5 rounded-full bg-amber-400 animate-pulse" />
                                            )}
                                        </button>
                                    </TooltipTrigger>
                                    <TooltipContent side="right">
                                        {isAuditMode ? 'Audit: ON' : 'Audit Mode'}
                                    </TooltipContent>
                                </Tooltip>
                            )}

                            <Tooltip>
                                <TooltipTrigger asChild>
                                    <button
                                        onClick={logout}
                                        className="w-full flex items-center justify-center p-4 rounded-2xl text-rose-500 hover:bg-rose-500/10 hover:text-rose-400 transition-all"
                                    >
                                        <LogOut className="w-6 h-6" />
                                    </button>
                                </TooltipTrigger>
                                <TooltipContent side="right">
                                    Sign Out
                                </TooltipContent>
                            </Tooltip>
                        </div>
                    )}
                </div>

                {/* Collapse Toggle */}
                <button
                    onClick={() => setCollapsed(!collapsed)}
                    className="absolute -right-4 top-24 w-8 h-8 rounded-2xl bg-sidebar border border-sidebar-border flex items-center justify-center shadow-md text-sidebar-foreground/50 hover:text-sidebar-foreground hover:bg-sidebar-accent transition-all z-50 hover:scale-110 active:scale-95"
                >
                    {collapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
                </button>
            </aside>
        </TooltipProvider>
    );
}
